/*!40000 ALTER TABLE `course` DISABLE KEYS */;
INSERT INTO `course` VALUES ('072aba94-5083-11f1-9abe-6c02e0d26821','JavaScript for Beginners','A practical introduction to JavaScript covering fundamentals such as variables, control flow, functions, DOM manipulation, and basic events. Students will build interactive web pages and small projects to apply concepts and reinforce learning. No prior programming experience required; hands-on exercises and quizzes guide progress.',NULL,'454cecad-4f80-11f1-ba5b-00090ffe0001','ef382f5a-4fb7-11f1-9abe-6c02e0d26821',80.00,70,'draft','2026-05-15 20:25:11','2026-05-15 20:25:20','/uploads/courses/1778865911626-javascript-for-beginners.png',8),('3f364be3-5143-11f1-9abe-6c02e0d26821','Database & SQL: Fundamentals to Practical Queries','Learn core database concepts, the relational model, and schema design including normalization. Gain hands-on experience writing SQL for selection, joins, aggregation, subqueries, and data modification. Practice with real-world labs using PostgreSQL/SQLite and learn basic indexing and query optimization to improve performance.',NULL,'454cf356-4f80-11f1-ba5b-00090ffe0001','0dc22a3c-4fb8-11f1-9abe-6c02e0d26821',110.00,70,'published','2026-05-16 19:21:09','2026-05-16 20:12:54','/uploads/courses/1778948469032-database-sql-fundamentals-to-practical-queries.png',8),('4d9de360-5082-11f1-9abe-6c02e0d26821','CSS Fundamentals','Learn core CSS concepts and techniques needed to build responsive, accessible websites. This hands-on course covers selectors, typography, color, layout with Flexbox and Grid, responsive design, and practical workflow tools like custom properties and basic preprocessors. By the end, you\'ll be able to style multi-page sites and implement modern layouts using real-world mini-projects.',NULL,'454cf180-4f80-11f1-ba5b-00090ffe0001','ef382f5a-4fb7-11f1-9abe-6c02e0d26821',50.00,70,'draft','2026-05-15 20:20:00','2026-05-16 17:26:29','/uploads/courses/1778865600322-css-fundamentals.png',6),('4f0dd6ed-2076-11f1-97b2-6c02e0d26821','Python Programming','This course introduces learners to the fundamentals of Python programming, one of the most widely used programming languages in software development, data science, artificial intelligence, and automation. Students will learn programming concepts such as variables, control structures, functions, and object-oriented programming while developing practical programs and solving real-world problems. The course gradually progresses from basic syntax to advanced concepts like file handling, modules, and working with external libraries.\r\n\r\nPython is known for its simple syntax, readability, and large ecosystem of libraries, making it an ideal language for beginners and professionals alike. By the end of this course, students will be able to write efficient Python programs and apply programming skills in various applications.',NULL,'fb9e6f39-4f78-11f1-ba5b-00090ffe0001',NULL,20.00,60,'published','2026-03-15 15:53:12','2026-05-17 12:50:55','/uploads/courses/course-4f0dd6ed-2076-11f1-97b2-6c02e0d26821-1773615294920.webp',3),('6c78daa9-507d-11f1-9abe-6c02e0d26821','HTML Fundamentals','Learn the core building blocks of web pages using semantic HTML, elements, attributes, and document structure. Hands-on exercises guide you through creating forms, tables, multimedia integration, and basic accessibility best practices. By the end of the course you\'ll be able to build well-structured, SEO-friendly HTML pages and prepare them for styling with CSS.',NULL,'454cf521-4f80-11f1-ba5b-00090ffe0001','ef382f5a-4fb7-11f1-9abe-6c02e0d26821',60.00,70,'draft','2026-05-15 19:45:04','2026-05-15 19:45:22','/uploads/courses/1778863504605-html-fundamentals.png',6),('a2fe49a9-507b-11f1-9abe-6c02e0d26821','Java Programming','A hands-on Java course that takes complete beginners to job-ready developers. Start with core syntax and object-oriented principles, then progress to collections, generics, streams, concurrency, and common libraries. Students build real-world projects, write unit tests, and complete a capstone application for their portfolio.',NULL,'454cfc91-4f80-11f1-ba5b-00090ffe0001',NULL,100.00,70,'draft','2026-05-15 19:32:17','2026-05-15 19:33:05','/uploads/courses/1778862737071-java-programming-zero-to-hero.png',12),('d6476901-4fbb-11f1-9abe-6c02e0d26821','Backend Fundamentals with Node.js','This course introduces the core concepts of backend development using Node.js and modern JavaScript. Students will learn how backend systems work, how servers communicate with clients, how APIs are built, how databases are connected, and how authentication and deployment are handled in real-world applications.\r\n\r\nBy the end of the course, learners will be able to build and deploy a complete RESTful backend application using Node.js, Express, and MongoDB.',NULL,'fb9e6f39-4f78-11f1-ba5b-00090ffe0001','05860d11-4fb8-11f1-9abe-6c02e0d26821',60.00,55,'draft','2026-05-14 20:39:19','2026-05-14 20:55:04','/uploads/courses/1778780359756-backend-fundamentals-with-node-js.png',4),('dde5cde4-4fcc-11f1-9abe-6c02e0d26821','Express.js API Development','Learn to build scalable RESTful APIs with Express.js, covering routing, middleware, error handling, and authentication. Hands-on lessons include building CRUD endpoints, input validation, testing, and integrating with databases like MongoDB. The final module covers deployment, monitoring, and performance optimizations for production-ready services.',NULL,'454cde6d-4f80-11f1-ba5b-00090ffe0001','05860d11-4fb8-11f1-9abe-6c02e0d26821',149.99,70,'draft','2026-05-14 22:41:13','2026-05-14 22:43:46','/uploads/courses/1778787673982-express-js-api-development.png',6),('ed1b33e8-5132-11f1-9abe-6c02e0d26821','TypeScript for Web Development','A hands-on course teaching TypeScript fundamentals and applying them to modern web development with React, Node.js, and DOM APIs. Learn static typing, advanced types, tooling, and migration strategies to improve code quality and catch bugs early. Includes practical projects, unit testing, and deployment guidance to build production-ready applications.',NULL,'454cf028-4f80-11f1-ba5b-00090ffe0001','ef382f5a-4fb7-11f1-9abe-6c02e0d26821',100.00,70,'draft','2026-05-16 17:24:19','2026-05-16 17:24:28','/uploads/courses/1778941459321-typescript-for-web-development.png',8);
/*!40000 ALTER TABLE `course` ENABLE KEYS */;
UNLOCK TABLES;

